import React, {useState, useRef} from 'react'
import styled from 'styled-components'
import clothing from './static/clothing.jpg'

const CardWrapper = styled.div `
display:flex;
flex-direction:column;
margin:30px 10px;
width:200px;
`

const CardImage = styled.div `
background-image:url(${clothing});
background-size:cover;
width:100%;
height:200px;
`

const ListingTime = styled.div `
font-size:0.7rem;
color:grey;
margin:5px 0;
`

const Hr = styled.div `
width:100%;
height:1px;
background-color:grey;
margin:5px 0;
`

const ListingTitleWrapper = styled.div `
display:flex;
justify-content:space-between;
margin:5px 0;
`

const ListingTitle = styled.div `
font-size:0.8rem;
font-weight:900;
`

const ListingSize = styled.div `
font-size:0.8rem;
font-weight:900;
`
const ListingContent = styled.div `
font-size:0.7rem;
`


const ListingFooterWrapper = styled.div `
display:flex;
justify-content:space-between;
margin:5px 0;
`

const ListingPrice = styled.div `
font-size:0.8rem;
font-weight:900;
`

const Love = styled.div `
font-size:0.7rem;
`

export default function ListingCard ({children}) {


	return (
		<CardWrapper>
			<CardImage></CardImage>
			<ListingTime>1 days Ago</ListingTime>
			<Hr/>
			<ListingTitleWrapper>
				<ListingTitle>DR. MARTENS × RICK</ListingTitle>
				<ListingSize>L</ListingSize>
			</ListingTitleWrapper>
			<ListingContent>The best dresses in the world</ListingContent>
			<ListingFooterWrapper>
				<ListingPrice>$600</ListingPrice>
				<Love>LOVE</Love>
			</ListingFooterWrapper>
		</CardWrapper>
	)
}
